public class ICStatus
	{
		private string m_EntityICStatusImagePath;

		private string m_EntityName;

		private string m_Time;

		private decimal m_EntityBalance;

		private int m_PartnersWithActivity;

		private int m_Pairings;

		private int m_PairingsUnbalanced;

		public string EntityICStatusImagePath
		{
			get
			{
				return m_EntityICStatusImagePath;
			}
			set
			{
				m_EntityICStatusImagePath = value;
			}
		}

		public string EntityName
		{
			get
			{
				return m_EntityName;
			}
			set
			{
				m_EntityName = value;
			}
		}

		public string Time
		{
			get
			{
				return m_Time;
			}
			set
			{
				m_Time = value;
			}
		}

		public decimal EntityBalance
		{
			get
			{
				return m_EntityBalance;
			}
			set
			{
				m_EntityBalance = value;
			}
		}

		public int PartnersWithActivity
		{
			get
			{
				return m_PartnersWithActivity;
			}
			set
			{
				m_PartnersWithActivity = value;
			}
		}

		public int Pairings
		{
			get
			{
				return m_Pairings;
			}
			set
			{
				m_Pairings = value;
			}
		}

		public int PairingsBalanced
		{
			get
			{
				if (m_Pairings > 0)
				{
					return checked(m_Pairings - m_PairingsUnbalanced);
				}
				return 0;
			}
		}

		public int PairingsUnbalanced
		{
			get
			{
				return m_PairingsUnbalanced;
			}
			set
			{
				m_PairingsUnbalanced = value;
			}
		}

		public ICStatus(string entityICStatusImagePath, string entityName, string time, decimal entityBalance, int partnersWithActivity, int pairings, int pairingsUnbalanced)
		{
			m_EntityICStatusImagePath = string.Empty;
			m_EntityName = string.Empty;
			m_Time = string.Empty;
			m_EntityBalance = default(decimal);
			m_PartnersWithActivity = 0;
			m_Pairings = 0;
			m_PairingsUnbalanced = 0;
			m_EntityICStatusImagePath = entityICStatusImagePath;
			m_EntityName = entityName;
			m_Time = time;
			m_EntityBalance = entityBalance;
			m_PartnersWithActivity = partnersWithActivity;
			m_Pairings = pairings;
			m_PairingsUnbalanced = pairingsUnbalanced;
		}
	}

public class ICDetail
	{
		private readonly DataCellPk m_DataCellPk;

		private readonly ICMatchTransaction m_ICTransaction;

		private readonly bool m_IsPrimaryEntity;

		private readonly bool m_IsExpOrAsset;

		private readonly bool m_IsDifference;

		private string m_EntityName;

		private string m_PartnerName;

		private int m_PartnerId;

		private string m_Account;

		private string m_DimensionDetails;

		private decimal m_ReportCurValue;

		private readonly bool m_ReportCurValueIsDerived;

		private string m_ReportCurLabel;

		private decimal m_EntityCurValue;

		private readonly bool m_EntityCurValueIsDerived;

		private string m_EntityCurLabel;

		private decimal m_PartnerCurValue;

		private readonly bool m_PartnerCurValueIsDerived;

		private string m_PartnerCurLabel;

		private readonly decimal m_PartnerBalance;

		private readonly decimal m_Tolerance;

		private readonly string m_NumberFormat;

		public DataCellPk DataCellPk => m_DataCellPk;

		public ICMatchTransaction ICTransaction => m_ICTransaction;

		public bool IsDifference => m_IsDifference;

		public bool ReportValueDerived => m_ReportCurValueIsDerived;

		public bool EntityValueDerived => m_EntityCurValueIsDerived;

		public bool PartnerValueDerived => m_PartnerCurValueIsDerived;

		public bool ShowDynamicDetaIndicatorForReportingCurrency
		{
			get
			{
				if (m_ReportCurValueIsDerived)
				{
					return !m_IsDifference;
				}
				return false;
			}
		}

		public bool ShowDynamicDetaIndicatorForEntityCurrency
		{
			get
			{
				if (m_EntityCurValueIsDerived)
				{
					return !m_IsDifference;
				}
				return false;
			}
		}

		public bool ShowDynamicDetaIndicatorForPartnerCurrency
		{
			get
			{
				if (PartnerValueDerived)
				{
					return !m_IsDifference;
				}
				return false;
			}
		}

		public bool CanSetStatus
		{
			get
			{
				if (IsDifference)
				{
					return false;
				}
				if (m_IsPrimaryEntity)
				{
					return true;
				}
				return false;
			}
		}

		public string PairingGroup
		{
			get
			{
				if (IsDifference)
				{
					return string.Empty;
				}
				if (m_IsPrimaryEntity)
				{
					return m_EntityName + " - " + m_PartnerName;
				}
				return m_PartnerName + " - " + m_EntityName;
			}
		}

		public string EntityName
		{
			get
			{
				return m_EntityName;
			}
			set
			{
				m_EntityName = value;
			}
		}

		public string PartnerName
		{
			get
			{
				return m_PartnerName;
			}
			set
			{
				m_PartnerName = value;
			}
		}

		public int PartnerId
		{
			get
			{
				return m_PartnerId;
			}
			set
			{
				m_PartnerId = value;
			}
		}

		public string Account
		{
			get
			{
				return m_Account;
			}
			set
			{
				m_Account = value;
			}
		}

		public string DimensionDetails
		{
			get
			{
				return m_DimensionDetails;
			}
			set
			{
				m_DimensionDetails = value;
			}
		}

		public string ReportCurValue => m_ReportCurValue.ToString(m_NumberFormat);

		public string ReportCurLabel
		{
			get
			{
				return m_ReportCurLabel;
			}
			set
			{
				m_ReportCurLabel = value;
			}
		}

		public string EntityCurValue => m_EntityCurValue.ToString(m_NumberFormat);

		public string EntityCurLabel
		{
			get
			{
				return m_EntityCurLabel;
			}
			set
			{
				m_EntityCurLabel = value;
			}
		}

		public string PartnerCurValue => m_PartnerCurValue.ToString(m_NumberFormat);

		public string PartnerCurLabel
		{
			get
			{
				return m_PartnerCurLabel;
			}
			set
			{
				m_PartnerCurLabel = value;
			}
		}

		public string PartnerBalanceHeader
		{
			get
			{
				if (IsPartnerBalanced)
				{
					return m_PartnerName;
				}
				string[] obj = new string[5] { m_PartnerName, "    ", null, null, null };
				decimal partnerBalance = m_PartnerBalance;
				obj[2] = partnerBalance.ToString(m_NumberFormat);
				obj[3] = " ";
				obj[4] = ReportCurLabel;
				return string.Concat(obj);
			}
		}

		public bool IsPartnerBalanced
		{
			get
			{
				if (decimal.Compare(Math.Abs(m_PartnerBalance), Math.Abs(m_Tolerance)) > 0)
				{
					return false;
				}
				return true;
			}
		}

		public decimal PartnerBalance => m_PartnerBalance;

		public ICDetail(DataCellPk dataCellPk, ICMatchTransaction icTransaction, bool isPrimaryEntity, bool isExpOrAsset, bool isDifference, string entityName, string partnerName, int partnerId, string account, string plugAccount, decimal reportCurvalue, string reportCurLabel, decimal entityCurValue, string entityCurLabel, decimal partnerCurValue, string partnerCurLabel, decimal partnerBalance, decimal tolerance, string numberFormat, bool isReportDerived, bool isEntityDerived, bool isPartnerDerived)
		{
			m_DataCellPk = null;
			m_ICTransaction = null;
			m_IsPrimaryEntity = false;
			m_IsExpOrAsset = false;
			m_EntityName = string.Empty;
			m_PartnerName = string.Empty;
			m_PartnerId = -1;
			m_Account = string.Empty;
			m_DimensionDetails = string.Empty;
			m_ReportCurValue = default(decimal);
			m_ReportCurValueIsDerived = false;
			m_ReportCurLabel = string.Empty;
			m_EntityCurValue = default(decimal);
			m_EntityCurValueIsDerived = false;
			m_EntityCurLabel = string.Empty;
			m_PartnerCurValue = default(decimal);
			m_PartnerCurValueIsDerived = false;
			m_PartnerCurLabel = string.Empty;
			m_PartnerBalance = default(decimal);
			m_Tolerance = default(decimal);
			m_NumberFormat = "N2";
			m_DataCellPk = dataCellPk;
			m_ICTransaction = icTransaction;
			m_IsPrimaryEntity = isPrimaryEntity;
			m_IsExpOrAsset = isExpOrAsset;
			m_IsDifference = isDifference;
			m_EntityName = entityName;
			m_PartnerName = partnerName;
			m_PartnerId = partnerId;
			m_Account = account;
			m_DimensionDetails = plugAccount;
			m_ReportCurValue = reportCurvalue;
			m_ReportCurValueIsDerived = isReportDerived;
			m_ReportCurLabel = reportCurLabel;
			m_EntityCurValue = entityCurValue;
			m_EntityCurValueIsDerived = isEntityDerived;
			m_EntityCurLabel = entityCurLabel;
			m_PartnerCurValue = partnerCurValue;
			m_PartnerCurValueIsDerived = isPartnerDerived;
			m_PartnerCurLabel = partnerCurLabel;
			m_PartnerBalance = partnerBalance;
			m_Tolerance = tolerance;
			m_NumberFormat = numberFormat;
		}
	}
